import json,sys
state=json.load(sys.stdin)
def find_resource(resources, addr):
    for r in resources:
        if r.get('address') == addr:
            return r
        if 'resources' in r:
            found = find_resource(r['resources'], addr)
            if found: return found
        if 'child_modules' in r:
            for m in r['child_modules']:
                if 'resources' in m:
                    found = find_resource(m['resources'], addr)
                    if found: return found
    return None
root = state.get('values', {}).get('root_module', {})
all_res = root.get('resources', [])
for cm in root.get('child_modules', []):
    all_res.extend(cm.get('resources', []))
waf = [r for r in all_res if 'waf' in r.get('address','').lower()]
print(json.dumps([r['address'] for r in waf], indent=2))
"

